var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"아! 이번 회수 작전에도 참여에 응해주셔서 감사드립니다!","JPN":"おお！　今回の回収作戦にご参加いただきありがとうございます！","ENG":"Oh, thank you for participating in the operation again.","TWN":"啊！非常感謝各位參加這次回收作戰！"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"본사는 지난 작전에서 성공적으로 생환한 태스크포스 베테랑 여러분의 재참여를 매우 기쁘게 받아들이고 있습니다.","JPN":"弊社は前回の作戦で生還したタスクフォースカンパニーのベテランの皆様の再参加を、大変嬉しく思います。","ENG":"Maxwell Corporation is very excited to see all of the surviving TASKFORCE combatants from the last operation.","TWN":"各位特遣勢力老兵在總公司上次作戰中成功生還，這次又參與了本公司的作戰，我們非常高興。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"이번 작전도 목적은 동일합니다.","JPN":"今回の作戦も目的は同じです。","ENG":"The goal is the same as the last operation.","TWN":"這次作戰的目標也一樣。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"제 2연구단지에 진입하여 실험자원을 회수한 뒤 돌아오십시오.","JPN":"第2研究団地に向かい実験資源を回収後、帰還してください。","ENG":"Infiltrate the Second Research Complex and retrieve research data.","TWN":"請進入第二研究園區回收實驗資源，然後返回。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"지난 번과 마찬가지로 정신이 오염된 선발대 용병들의 오인사격에 주의하시기 바랍니다.","JPN":"前回同様、精神が汚染された先発隊傭兵たちの誤認射撃にご注意ください。","ENG":"Like the last time, beware of friendly fire from the mentally broken mercenaries.","TWN":"與上次一樣，在污染地帶請各位注意精神遭污染的先遣隊傭兵。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"안타깝게도 그들은 저희가 제공하는 1회용 이터니움 실드의 지속시간이 한 시간이라는 걸 잊어버린 모양이더군요.","JPN":"残念なことに、彼らは弊社が提供する使い捨てエタニウムシールドの効果時間が1時間ということを忘れてしまったようです。","ENG":"Unfortunately, it seems they forgot the fact that the effects of disposable Eternium shields that we gave them only last for an hour.","TWN":"我們為他們提供的一次性永恆之金護盾持續時長為1小時，但很遺憾的是，他們似乎忘記了這件事。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 그리고 한 가지 추가로 당부의 말씀 드리고자 합니다.","JPN":"ああ、それからもう一つお願いをさせていただきます。","ENG":"Ah, and there's something else I would like to tell you.","TWN":"啊，我還有一點想向各位強調的。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"현장에 참여했던 일부 카운터 용병들이 저희 연구단지에서 일어난 침식현상이 통상적인 침식현상과 다르다는 제보가 다수 있었다더군요.","JPN":"現場に参加した一部のカウンター傭兵から、当研究団地で起きた侵食現象が通常の侵食現象と異なるという情報が多数あったようです。","ENG":"There have been multiple reports from mercenary Counters that the condition of Corruption occurring at our research complex seems different from previously known cases.","TWN":"在現場參與作戰的一部分制裁者傭兵向我們多次發送資訊說，在研究園區發生的侵蝕現象非比尋常。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"왠지는 모르겠지만, 그 침식파가 카운터의 CRF를 억제한다고 합니다.","JPN":"なぜかはわかりませんが、その侵食波がカウンターのCRFを抑制するようです。","ENG":"We have yet to figure out why, but the Corruption rays released in the area seem to be suppressing the CRF of Counters.","TWN":"雖然不知為何，但據說這侵蝕波會抑制制裁者的CRF。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":null,"text":{"KOREA":"그와 관련해서 저희 회사가 암암리에 대 카운터용 장비를 개발하고 있었던 게 아니냐는 식의 여러 음해와 모함이 있었다고 합니다만......","JPN":"それに関して弊社が暗暗裏に対カウンター用装備を開発していたのではないかと様々な陰謀と計略の噂が出回っているそうですが……","ENG":"This has caused all kinds of rumors and slander accusing Maxwell Corporation of developing anti-Counter gear,","TWN":"對此，有很多人暗害誣陷我們公司，說我們在暗中研發對抗制裁者的裝備等等，不過……"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"연구단지에서 일어난 현상은 우연한 천재지변일 뿐이라는 점을 알아주셨으면 좋겠습니다.","JPN":"研究団地で起きた現象は偶然発生した天災地変に過ぎないということを理解いただければと思います。","ENG":"but I assure you, what happened in the research complex was nothing but an unfortunate natural disaster.","TWN":"我希望各位知道，研究園區發生的現象只是偶然發生的自然災害。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"아무튼...... 그 특이한 침식파가 검출되는 장소에 접근하실 땐 카운터 여러분들의 접근에 주의가 필요할 겁니다.","JPN":"とにかく……その独特な侵食波が検出される場所に近づく際は、カウンターの皆様にご注意いただく必要があるでしょう。","ENG":"Even so, it is advised that all Counter combatants use extra caution when approaching areas filled with these peculiar Corruption rays.","TWN":"總之……如果要進入的場所勘測出異常侵蝕波，請各位制裁者在接近時多留意一下。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 다녀오십시오. 무사귀환을 기원합니다.","JPN":"それではよろしくお願いいたします。無事のご帰還を祈ります。","ENG":"Then, I wish you good luck. I hope to see every one of you in one piece.","TWN":"那請各位出發吧。望各位平安歸還。"},"stage":{"bg":"BLACK","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};